CREATE INDEX "IX_Budgets_UserId_MonthYear" ON "Budgets" ("UserId", "MonthYear");

CREATE INDEX "IX_Categories_UserId" ON "Categories" ("UserId");

CREATE UNIQUE INDEX "IX_Currencies_Code" ON "Currencies" ("Code");

CREATE INDEX "IX_Expenses_CategoryId" ON "Expenses" ("CategoryId");

CREATE INDEX "IX_Expenses_UserId_ExpenseDate" ON "Expenses" ("UserId", "ExpenseDate" DESC);

CREATE INDEX "IX_Expenses_WalletId" ON "Expenses" ("WalletId");

CREATE INDEX "IX_RecurringExpenses_CategoryId" ON "RecurringExpenses" ("CategoryId");

CREATE INDEX "IX_RecurringExpenses_NextDueDate_IsActive" ON "RecurringExpenses" ("NextDueDate", "IsActive");

CREATE INDEX "IX_RecurringExpenses_UserId" ON "RecurringExpenses" ("UserId");

CREATE INDEX "IX_RecurringExpenses_WalletId" ON "RecurringExpenses" ("WalletId");

CREATE INDEX "IX_Users_CurrencyId" ON "Users" ("CurrencyId");

CREATE UNIQUE INDEX "IX_Users_Email" ON "Users" ("Email");

CREATE INDEX "IX_Wallets_CurrencyId" ON "Wallets" ("CurrencyId");

CREATE INDEX "IX_Wallets_UserId" ON "Wallets" ("UserId");

CREATE INDEX "IX_WalletTransfers_FromWalletId" ON "WalletTransfers" ("FromWalletId");

CREATE INDEX "IX_WalletTransfers_ToWalletId" ON "WalletTransfers" ("ToWalletId");

CREATE INDEX "IX_WalletTransfers_UserId" ON "WalletTransfers" ("UserId");

